mapper.select:
SELECT email_log_type_id, email_doc_type
FROM email_log_types
WHERE email_log_id = #{emailLogId}

SELECT email_log_attachment_id, email_attachment_filename
FROM email_log_attachments
WHERE email_log_id = #{emailLogId}

SELECT email_log_id, client_id, po_id, email_title, email_recipient_name,
       email_recipient_email, email_sender_id, email_status, email_sent_at, created_at
FROM email_logs


        AND client_id = #{clientId}


        AND po_id = #{poId}


        AND email_status = #{emailStatus}


        AND email_sender_id = #{emailSenderId}


        AND (email_title LIKE CONCAT('%', #{keyword}, '%'))


        AND email_sent_at >= #{dateFrom}


        AND email_sent_at <= #{dateTo}


ORDER BY created_at DESC
